function dateOrdinalNumber(number, localeNumber) {
  if (number > 18 && number <= 31) {
    return localeNumber + "а¶ґаІЗ";
  } else {
    switch (number) {
      case 1:
        return localeNumber + "а¶≤а¶Њ";
      case 2:
      case 3:
        return localeNumber + "а¶∞а¶Њ";
      case 4:
        return localeNumber + "а¶†а¶Њ";
      default:
        return localeNumber + "а¶З";
    }
  }
}

const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);
  const localeNumber = numberToLocale(number);
  const unit = options?.unit;

  if (unit === "date") {
    return dateOrdinalNumber(number, localeNumber);
  }
  if (number > 10 || number === 0) return localeNumber + "а¶§а¶Ѓ";

  const rem10 = number % 10;
  switch (rem10) {
    case 2:
    case 3:
      return localeNumber + "аІЯ";
    case 4:
      return localeNumber + "а¶∞аІНа¶•";
    case 6:
      return localeNumber + "а¶ЈаІНа¶†";
    default:
      return localeNumber + "а¶Ѓ";
  }
};

